SELECT COUNT(DISTINCT PB.PK) AS TOTAL FROM LATTES_P_PRODBIB LP JOIN LATTES_PRODBIB PB ON PB.PK = LP.FK_PRODBIB JOIN SERVIDOR S ON S.PK_SIAPE = LP.FK_SIAPE WHERE LOWER(PB.TIPO) = LOWER('capitulo de livro') AND TRIM(PB.ANO) = '2020' AND LOWER(S.GENERO) = LOWER('masculino') AND (LOWER(S.SIGLA_CAMPUS) = LOWER('gyn') OR LOWER(S.CAMPUS_ATUAL) LIKE LOWER('%goiania%')) AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%hist%'